from __future__ import annotations

from collections.abc import Callable
from decimal import Decimal
from typing import TYPE_CHECKING

from djmoney.money import Money
from mypy_extensions import DefaultNamedArg

from cloud.businessunits.models import BusinessUnit
from cloud.financial.invoicing import money
from cloud.location.enums import Country
from cloud.priceengine.dataclasses import PRICE_SPEC_PRECISION, MonthlyPayment

if TYPE_CHECKING:
    from collections.abc import Iterator
    from typing import TypeAlias


MonthlyFunc: TypeAlias = Callable[
    [int, DefaultNamedArg(int, 'term'), DefaultNamedArg(int, 'escalation_per_year')], Decimal  # noqa: F821
]


def monthly_interest_rate(
    interest_basis_points: int, *, term: int = 0, escalation_per_year: int = 0
) -> Decimal:
    """
    Return monthly interest rate.
    If escalation is set add escalator times year
    """
    if escalation_per_year > 0:
        interest_basis_points += int(term / 12) * escalation_per_year
    interest_rate = Decimal(interest_basis_points) / 10000
    return interest_rate / Decimal(12)


def make_per_month_func(
    interest_basis_points: int, num_terms: int, monthly_func: MonthlyFunc = monthly_interest_rate
) -> Callable[[Money], Money]:
    """
    Return function which calculates per month amounts with interest rate and
    num terms fixed.
    """

    def per_month(total: Money) -> Money:
        return monthly_payment(interest_basis_points, num_terms, total, monthly_func)

    return per_month


def monthly_payment(
    interest_basis_points: int,
    num_terms: int,
    start_balance: Money,
    monthly_func: MonthlyFunc = monthly_interest_rate,
    *,
    current_term: int = 0,
    escalation_per_year: int = 0,
    precision: int = PRICE_SPEC_PRECISION,
) -> Money:
    """Return monthly payment for a fixed rate loan."""
    if interest_basis_points == 0:
        result = start_balance / num_terms
    elif escalation_per_year > 0:
        rate = monthly_func(interest_basis_points, term=current_term, escalation_per_year=escalation_per_year)
        result = abs(calculate_pmt(start_balance, rate, num_terms))
    else:
        rate = monthly_func(interest_basis_points, term=current_term, escalation_per_year=escalation_per_year)
        result = start_balance * (rate / (1 - (1 + rate) ** -num_terms))
    return money.force_money_round(result, precision)


def start_balance(
    interest_basis_points: int,
    num_terms: int,
    monthly_payment: Money,
    monthly_func: MonthlyFunc = monthly_interest_rate,
    precision: int = 0,
) -> Money:
    """Return start balance for a fixed rate loan given the monthly payment."""
    if interest_basis_points == 0:
        result = monthly_payment * num_terms
    else:
        rate = monthly_func(interest_basis_points)
        result = monthly_payment * ((1 - (1 + rate) ** -num_terms) / rate)
    return money.force_money_round(result, precision)


def end_balance(
    interest_basis_points: int,
    num_terms: int,
    start_balance: Money,
    term_n: int,
    precision: int = 2,
) -> Money:
    """Return balance after term N of a fixed rate loan."""
    monthly = monthly_payment(
        interest_basis_points,
        num_terms,
        start_balance,
        precision=10,
        current_term=term_n,
    )
    if interest_basis_points == 0:
        return money.force_money_round(start_balance - monthly * term_n, precision)
    else:
        interest_rate = Decimal(interest_basis_points) / 10000
        return money.force_money_round(
            (
                (start_balance - ((monthly * 12) / interest_rate)) * (1 + (interest_rate / 12)) ** term_n
                + monthly * (12 / interest_rate)
            ),
            precision,
        )


def interest_amount(
    interest_basis_points: int,
    num_terms: int,
    start_balance: Money,
    term_n: int,
    precision: int,
) -> Money:
    """Return interest amount for term N of a fixed rate loan."""
    prev_term = term_n - 1
    if prev_term < 0:
        return Money(0, start_balance.currency)
    start_balance = end_balance(
        interest_basis_points, num_terms, start_balance, prev_term, precision=precision
    )
    result = start_balance * monthly_interest_rate(interest_basis_points, term=prev_term)
    return money.force_money_round(result, precision)


def calculate_minimum_buyout_amount_excl_vat(market: Country, initial_system_value_excl_vat: Money) -> Money:
    """
    Once upon a time, Otovo had a linear down-payment plan, which
    completely paid off a subscription PV-system, and mean the customer
    would own their leased system after 240 terms.

    This turned out to be too similar to a financial lease, which is an asset type
    we don't want to sell, as it would classify the company as more of a bank, which
    comes with really strict compliance requirements.

    Instead of selling "financial leases" we want to sell "operational leases", and for that
    purpose we've added a floor to the residual value of a system.

    This function currently encapsulates the logic for what the minimum amount should be.
    The plan is to remove the flat AT rate once we've landed on a final design for the
    percentage-based rate.
    """
    match market:
        # Austria needs a €500 remainder at the end of the rendered repayment plan
        case Country.AT:
            minimum_buyout_amount_excl_vat = Money(500, 'EUR')
        # Remaining markets (and soon Austria too) will have their minimum buyout amounts
        # set as a percentage rate in the business config
        case _:
            minimum_buyout_amount_excl_vat = (
                BusinessUnit.get_central_unit_for_country(
                    market
                ).config.leasing_minimum_buyout_amount_percentage
                * initial_system_value_excl_vat
            )

    return minimum_buyout_amount_excl_vat


def monthly_payments(
    interest_basis_points: int,
    num_terms: int,
    start_balance_excl_vat: Money,
    market: Country,
    *,
    escalation_per_year: int = 0,
    precision: int = PRICE_SPEC_PRECISION,
) -> Iterator[MonthlyPayment]:
    """Return monthly payments for a fixed rate loan.
    If esclation_per_year is set, recalulate the total per month after escalating the interest rate accordingly
    """

    total = monthly_payment(interest_basis_points, num_terms, start_balance_excl_vat)
    last_end_balance = start_balance_excl_vat
    minimum_buyout_amount_excl_vat = calculate_minimum_buyout_amount_excl_vat(
        market=market, initial_system_value_excl_vat=start_balance_excl_vat
    )
    for term in range(1, num_terms + 1):
        interest = interest_amount(
            interest_basis_points, num_terms, start_balance_excl_vat, term, precision=precision
        )

        # On the last month pay the remainder.
        if term == num_terms:
            total = last_end_balance
            interest = Money(0, start_balance_excl_vat.currency)

        principal = total - interest
        last_end_balance = last_end_balance - principal

        if escalation_per_year > 0:
            total_with_escalation = monthly_payment(
                interest_basis_points,
                num_terms,
                start_balance_excl_vat,
                current_term=term - 1,
                escalation_per_year=escalation_per_year,
                precision=precision,
            )
            interest = total_with_escalation - principal

        yield MonthlyPayment(
            market=market,
            term=term,
            principal=money.force_money_round(principal, precision),
            interest=money.force_money_round(interest, precision),
            remainder=money.force_money_round(last_end_balance, precision),
            minimum_buyout_amount_excl_vat=minimum_buyout_amount_excl_vat,
            precision=precision,
        )


def calculate_pmt(present_value: Money, monthly_interest_rate: Decimal, num_periods: int) -> Money:
    """
    Calculate the Payment (PMT) for a loan or investment.

    Parameters:
    - present_value (Money): The present value of the loan or investment.
    - monthly_interest_rate (int): The monthly interest rate in Decimal
    - num_periods (int): The number of payment periods.

    Returns:
    - Money: The calculated payment amount (PMT).

    Formula:
    PMT = PV * (r * (1 + r)^n) / ((1 + r)^n - 1)

    Where:
    PV = Present Value
    r = Monthly interest rate (annual rate / 12)
    n = Number of payment periods
    """

    if monthly_interest_rate <= 0 or num_periods <= 0:
        raise ValueError('Interest rate (in basis points) and number of periods must be greater than zero.')

    # Calculate PMT using the formula
    pmt = (
        present_value
        * (monthly_interest_rate * (1 + monthly_interest_rate) ** num_periods)
        / ((1 + monthly_interest_rate) ** num_periods - Decimal(1))
    )

    return pmt
